<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Bouncing Ball Physics Playground</title>
  <style>
    * { box-sizing: border-box; }
    body {
      margin: 0;
      min-height: 100vh;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      background: #0f0f13;
      color: #e8e8e8;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    }
    h1 { margin: 0 0 0.5rem; font-weight: 600; letter-spacing: 0.5px; }
    .wrap { text-align: center; }
    canvas#sim {
      display: block;
      margin: 1rem auto;
      background: #161622;
      border-radius: 14px;
      box-shadow: 0 12px 40px rgba(0, 0, 0, 0.55);
      cursor: crosshair;
    }
    .controls {
      display: flex;
      gap: 1rem;
      justify-content: center;
      margin-bottom: 0.5rem;
    }
    button {
      padding: 0.6rem 1.4rem;
      font-size: 1rem;
      border: none;
      border-radius: 8px;
      background: #2a2a3a;
      color: #fff;
      cursor: pointer;
      transition: transform 0.08s ease, background 0.15s ease;
    }
    button:hover { background: #3a3a50; }
    button:active { transform: scale(0.96); }
    .hint { color: #888; font-size: 0.9rem; margin-top: 0.5rem; }
  </style>
</head>
<body>
  <div class="wrap">
    <h1>Bouncing Ball Playground</h1>
    <canvas id="sim" width="600" height="600"></canvas>
    <div class="controls">
      <button id="drop">Drop</button>
      <button id="play">Play</button>
      <button id="clear">Clear</button>
    </div>
    <div class="hint">Click the canvas to spawn a ball.</div>
  </div>

  <script>
    (function () {
      const canvas = document.getElementById('sim');
      const ctx = canvas.getContext('2d');
      const W = canvas.width;
      const H = canvas.height;

      const G = 0.5;            // gravity per unit time
      const RESTITUTION = 0.8;  // energy loss on bounce
      const DEFAULT_R = 15;

      let balls = [];
      let ripples = [];
      let playing = false;
      let lastFrameTime = 0;
      let rafId = null;

      function randColor() {
        const hue = Math.floor(Math.random() * 360);
        return `hsl(${hue}, 80%, 60%)`;
      }

      function addBall(x, y, vx = 0, vy = 0, r = DEFAULT_R) {
        r = Math.max(2, r);
        // Keep the ball inside the canvas from the start.
        x = Math.max(r, Math.min(W - r, x));
        y = Math.max(r, Math.min(H - r, y));
        balls.push({ x, y, vx, vy, r, color: randColor() });
        draw();
      }

      function clearBalls() {
        balls = [];
        ripples = [];
        draw();
      }

      function step(dt = 1) {
        if (dt <= 0) {
          draw();
          return;
        }
        const steps = Math.max(1, Math.ceil(dt));
        const sdt = dt / steps;

        for (let s = 0; s < steps; s++) {
          for (const b of balls) {
            b.vy += G * sdt;
            b.x += b.vx * sdt;
            b.y += b.vy * sdt;

            if (b.x - b.r < 0) {
              b.x = b.r;
              b.vx = -b.vx * RESTITUTION;
            } else if (b.x + b.r > W) {
              b.x = W - b.r;
              b.vx = -b.vx * RESTITUTION;
            }

            if (b.y - b.r < 0) {
              b.y = b.r;
              b.vy = -b.vy * RESTITUTION;
            } else if (b.y + b.r > H) {
              b.y = H - b.r;
              b.vy = -b.vy * RESTITUTION;
            }
          }
        }

        // Fade ripples
        for (let i = ripples.length - 1; i >= 0; i--) {
          ripples[i].life -= dt;
          if (ripples[i].life <= 0) ripples.splice(i, 1);
        }

        draw();
      }

      function draw() {
        ctx.clearRect(0, 0, W, H);

        // Subtle grid
        ctx.strokeStyle = "rgba(255,255,255,0.04)";
        ctx.lineWidth = 1;
        const grid = 50;
        for (let x = 0; x <= W; x += grid) {
          ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
        }
        for (let y = 0; y <= H; y += grid) {
          ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
        }

        // Ripples
        for (const rp of ripples) {
          const alpha = Math.max(0, rp.life / rp.maxLife);
          ctx.beginPath();
          ctx.arc(rp.x, rp.y, rp.r * (1 + (rp.maxLife - rp.life) / rp.maxLife * 2), 0, Math.PI * 2);
          ctx.strokeStyle = `rgba(255,255,255,${alpha * 0.4})`;
          ctx.lineWidth = 2;
          ctx.stroke();
        }

        // Balls
        for (const b of balls) {
          ctx.beginPath();
          ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
          const grad = ctx.createRadialGradient(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1, b.x, b.y, b.r);
          grad.addColorStop(0, "#fff");
          grad.addColorStop(0.3, b.color);
          grad.addColorStop(1, "rgba(0,0,0,0.35)");
          ctx.fillStyle = grad;
          ctx.shadowColor = b.color;
          ctx.shadowBlur = 15;
          ctx.fill();
          ctx.shadowBlur = 0;
          ctx.strokeStyle = "rgba(255,255,255,0.2)";
          ctx.lineWidth = 1;
          ctx.stroke();
        }
      }

      function togglePlay() {
        playing = !playing;
        document.getElementById('play').textContent = playing ? 'Pause' : 'Play';
        if (playing) {
          lastFrameTime = performance.now();
          rafId = requestAnimationFrame(loop);
        } else if (rafId) {
          cancelAnimationFrame(rafId);
          rafId = null;
        }
      }

      function loop(now) {
        if (!playing) return;
        const dt = Math.min(3, (now - lastFrameTime) / (1000 / 60)); // normalize to ~60fps steps
        lastFrameTime = now;
        step(dt);
        rafId = requestAnimationFrame(loop);
      }

      function canvasPointFromEvent(e) {
        const rect = canvas.getBoundingClientRect();
        const scaleX = canvas.width / rect.width;
        const scaleY = canvas.height / rect.height;
        return {
          x: (e.clientX - rect.left) * scaleX,
          y: (e.clientY - rect.top) * scaleY
        };
      }

      canvas.addEventListener('pointerdown', (e) => {
        const p = canvasPointFromEvent(e);
        addBall(p.x, p.y, (Math.random() - 0.5) * 4, (Math.random() - 0.5) * 4);
        ripples.push({ x: p.x, y: p.y, r: 5, life: 20, maxLife: 20 });
      });

      document.getElementById('drop').addEventListener('click', () => {
        const r = DEFAULT_R;
        addBall(
          r + Math.random() * (W - 2 * r),
          r + 20,
          (Math.random() - 0.5) * 12,
          Math.random() * 4
        );
      });

      document.getElementById('play').addEventListener('click', togglePlay);
      document.getElementById('clear').addEventListener('click', clearBalls);

      // Public API required for grading
      window.sim = {
        w: W,
        h: H,
        balls() {
          return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
        },
        addBall,
        clear: clearBalls,
        step
      };

      // Initial draw
      draw();
    })();
  </script>
</body>
</html>
